// client/js/pages/admin-dispensas.js

import { db } from '../firebase-config.js';
import { collection, getDocs, getDoc, doc, deleteDoc, updateDoc, setDoc } from "https://www.gstatic.com/firebasejs/10.8.1/firebase-firestore.js";

let loadedRequests = []; 
let currentTemplate = ""; 

async function loadHtml2Pdf() {
    if (window.html2pdf) return;
    return new Promise(resolve => {
        const s = document.createElement('script');
        s.src = 'https://cdnjs.cloudflare.com/ajax/libs/html2pdf.js/0.10.1/html2pdf.bundle.min.js';
        s.onload = resolve;
        document.head.appendChild(s);
    });
}
// ============================================================================
// 1. COLE AQUI OS CÓDIGOS BASE64 (Mantenha as aspas "")
// ============================================================================
const imgHeaderBase64 = "data:image/png;base64,";
const imgFooterBase64 = "data:image/png;base64,";

// ============================================================================
// ESTRUTURA DO DOCUMENTO PDF (COM AS IMAGENS BASE64)
// ============================================================================
const defaultHtmlTemplate = `
<div id="print-area" style="width: 210mm; height: 295mm; overflow: hidden; padding: 0; margin: 0; background: #fff; font-family: 'Arial', sans-serif; position: relative; box-sizing: border-box;">
    
    <div style="width: 100%; padding-top: 10mm; box-sizing: border-box;">
        <img src="${imgHeaderBase64}" style="width: 90%; margin-left: 1.5cm; display: block;">
    </div>

    <div style="padding: 5mm 20mm; color: #000; line-height: 1.6; font-size: 11pt; text-align: justify;">
        <p style="text-align: right; margin-bottom: 30px;">Rio de Janeiro, {{Datahoje}}.</p>
        <p style="font-weight: bold; margin-bottom: 20px;">A instituição<br>{{instituição}}<br>{{responsável}}</p>
        <p style="font-weight: bold; text-decoration: underline; margin-bottom: 30px;">Assunto: Declaração de Convocação e Dispensa</p>
        <p>Encaminhamos a V.S.ª conforme preceitua o artigo 84, em seus parágrafos 01 e 02, da lei número 9.615 de 24 de março de 1988, a <b>CONVOCAÇÃO</b> e <b>SOLICITAÇÃO DE DISPENSA</b> para integrar representação desportiva nacional {{pron_sr}} <b>{{Nome}}</b> {{pron_registrado}} no CPF sob o Nº <b>{{CPF}}</b> e {{pron_portador}} do RG <b>{{RG}}</b>.</p>
        <p>Este estará atuando na condição de <b>{{ÁRBITRO}}</b> na execução do <b>{{COMPETIÇÃO}}</b> a ser realizado na cidade de <b>{{LOCAL}}</b>, no período de <b>{{Período1}}</b> a <b>{{Período2}}</b>.</p>
        <p>Esperançosos de poder contar com a gentil colaboração de V.Sª que agradecemos antecipadamente, valemo-nos do ensejo para enviar nossas cordiais saudações.</p>
        <p style="margin-top: 30px;">Atenciosamente,</p>
    </div>

    <div style="position: absolute; bottom: 0; left: 0; width: 100%;">
        <img src="${imgFooterBase64}" style="width: 100%; display: block;">
    </div>
</div>
`;

export async function renderAdminDispensas(root) {
    root.innerHTML = `<div style="padding:40px; color:white; text-align:center;">Carregando Gerenciador...</div>`;

    try {
        await loadHtml2Pdf();
        const reqSnap = await getDocs(collection(db, "exemption_requests"));
        loadedRequests = [];
        reqSnap.forEach(d => { loadedRequests.push({ id: d.id, ...d.data() }); });

        loadedRequests.sort((a, b) => (b.created_at?.toMillis() || 0) - (a.created_at?.toMillis() || 0));

        const configSnap = await getDoc(doc(db, "settings", "pdf_template_html"));
        currentTemplate = configSnap.exists() ? configSnap.data().html : defaultHtmlTemplate;

        renderTable(root);
    } catch (error) {
        root.innerHTML = `<div style="color:red; padding:20px;">Erro ao carregar os dados: ${error.message}</div>`;
    }
}

function renderTable(root) {
    const styles = `<style>
        .admin-wrapper { padding: 40px 20px; font-family: sans-serif; background: #f8fafc; min-height: 100vh; }
        .admin-container { max-width: 1300px; margin: 0 auto; background: white; border-radius: 12px; box-shadow: 0 4px 6px rgba(0,0,0,0.1); overflow: hidden; border: 1px solid #e2e8f0; }
        .admin-header { padding: 25px; border-bottom: 1px solid #e2e8f0; display: flex; justify-content: space-between; align-items: center; background: #fff; }
        .dispensas-table { width: 100%; border-collapse: collapse; }
        .dispensas-table th { background: #f1f5f9; padding: 15px; text-align: left; font-size: 13px; color: #475569; text-transform: uppercase; }
        .dispensas-table td { padding: 15px; border-bottom: 1px solid #e2e8f0; font-size: 14px; color: #1e293b; }
        .btn-action { padding: 8px 12px; border: none; border-radius: 6px; cursor: pointer; font-weight: 600; margin-right: 4px; font-size: 12px; transition: 0.2s; }
        .btn-pdf { background: #10b981; color: white; } .btn-pdf:hover { background: #059669; }
        .btn-edit { background: #fef9c3; color: #d97706; } .btn-edit:hover { background: #fef08a; }
        .btn-del { background: #fef2f2; color: #dc2626; } .btn-del:hover { background: #fee2e2; }
        .modal { position: fixed; top: 0; left: 0; width: 100%; height: 100%; background: rgba(0,0,0,0.7); display: none; justify-content: center; align-items: center; z-index: 1000; }
        .modal-content { background: white; padding: 30px; border-radius: 12px; width: 95%; max-width: 800px; max-height: 90vh; overflow-y: auto; }
        .form-group { margin-bottom: 15px; } .form-group label { display:block; font-weight:bold; margin-bottom:5px; font-size:13px; }
        .form-group input { width:100%; padding:10px; border:1px solid #ddd; border-radius:6px; box-sizing: border-box; }
        .row-flex { display: flex; gap: 10px; }
    </style>`;

    let rowsHtml = loadedRequests.map(req => {
        const u = req.snapshot_user || {};
        const emp = req.snapshot_employer || {};
        const e = req.snapshot_event || {};
        const statusIcon = req.status === 'APPROVED' ? '✅' : '🔴';
        
        return `<tr>
            <td>${statusIcon} <b>${u.nome || u.nome_completo}</b><br><small>${u.rg || 'RG?'} | ${u.cpf || 'CPF?'}</small></td>
            <td>${e.nome_campeonato}<br><small>${e.funcao || req.role_in_event}</small></td>
            <td>${emp.nome_local || 'A Instituição'}<br><small>${emp.nome_responsavel || ''}</small></td>
            <td>
                <button class="btn-action btn-pdf" onclick="window.generateFinalPdf('${req.id}')">📄 PDF</button>
                <button class="btn-action btn-edit" onclick="window.openEditModal('${req.id}')">✏️ Editar</button>
                <button class="btn-action btn-del" onclick="window.deleteDispensa('${req.id}')">🗑️ Excluir</button>
            </td>
        </tr>`;
    }).join('');

    root.innerHTML = `
        ${styles}
        <div class="admin-wrapper">
            <div class="admin-container">
                <div class="admin-header">
                    <h2>🛡️ Gerenciamento de Dispensas</h2>
                    <button class="btn-action btn-edit" style="background:#0f172a; color:white; padding:10px 15px;" onclick="window.openTemplateEditor()">⚙️ Modelo HTML (Avançado)</button>
                </div>
                <table class="dispensas-table">
                    <thead><tr><th>Árbitro / Docs</th><th>Evento / Função</th><th>Instituição</th><th>Ações</th></tr></thead>
                    <tbody>${rowsHtml}</tbody>
                </table>
            </div>
        </div>

        <div id="editorModal" class="modal"><div class="modal-content">
            <h3>Editor de Modelo (HTML)</h3>
            <textarea id="tpl-html" style="width:100%; height:450px; font-family:monospace; padding:10px;">${currentTemplate}</textarea>
            <div style="margin-top:20px; display:flex; justify-content:flex-end; gap:10px;">
                <button class="btn-action" onclick="document.getElementById('editorModal').style.display='none'">Cancelar</button>
                <button class="btn-action btn-pdf" onclick="window.saveTemplate()">💾 Salvar Modelo</button>
            </div>
        </div></div>

        <div id="editModal" class="modal"><div class="modal-content">
            <h3>Editar Pedido</h3>
            <input type="hidden" id="edit-id">
            <div class="row-flex">
                <div class="form-group" style="flex:2;"><label>Nome</label><input type="text" id="edit-nome"></div>
                <div class="form-group" style="flex:1;"><label>Gênero (M/F)</label><input type="text" id="edit-genero"></div>
            </div>
            <div class="row-flex">
                <div class="form-group" style="flex:1;"><label>RG</label><input type="text" id="edit-rg"></div>
                <div class="form-group" style="flex:1;"><label>CPF</label><input type="text" id="edit-cpf"></div>
            </div>
            <div class="form-group"><label>Instituição</label><input type="text" id="edit-inst"></div>
            <div class="form-group"><label>Responsável</label><input type="text" id="edit-resp"></div>
            <div class="row-flex">
                <div class="form-group" style="flex:1;"><label>Data Início</label><input type="text" id="edit-ini"></div>
                <div class="form-group" style="flex:1;"><label>Data Fim</label><input type="text" id="edit-fim"></div>
            </div>
            <div style="margin-top:20px; display:flex; justify-content:flex-end; gap:10px;">
                <button class="btn-action" onclick="document.getElementById('editModal').style.display='none'">Cancelar</button>
                <button class="btn-action btn-pdf" onclick="window.saveDispensaEdit()">💾 Salvar</button>
            </div>
        </div></div>
    `;

    // Funções
    window.openTemplateEditor = () => { document.getElementById('editorModal').style.display = 'flex'; };
    window.saveTemplate = async () => {
        const html = document.getElementById('tpl-html').value;
        await setDoc(doc(db, "settings", "pdf_template_html"), { html });
        currentTemplate = html;
        document.getElementById('editorModal').style.display = 'none';
        alert("Modelo salvo!");
    };

    window.openEditModal = (id) => {
        const req = loadedRequests.find(r => r.id === id);
        document.getElementById('edit-id').value = id;
        document.getElementById('edit-nome').value = req.snapshot_user.nome || req.snapshot_user.nome_completo || '';
        document.getElementById('edit-genero').value = req.snapshot_user.genero || 'M';
        document.getElementById('edit-rg').value = req.snapshot_user.rg || '';
        document.getElementById('edit-cpf').value = req.snapshot_user.cpf || '';
        document.getElementById('edit-inst').value = req.snapshot_employer.nome_local || '';
        document.getElementById('edit-resp').value = req.snapshot_employer.nome_responsavel || '';
        document.getElementById('edit-ini').value = req.snapshot_event.data_inicio || '';
        document.getElementById('edit-fim').value = req.snapshot_event.data_fim || '';
        document.getElementById('editModal').style.display = 'flex';
    };

    window.saveDispensaEdit = async () => {
        const id = document.getElementById('edit-id').value;
        const newData = {
            snapshot_user: { nome: document.getElementById('edit-nome').value, genero: document.getElementById('edit-genero').value, rg: document.getElementById('edit-rg').value, cpf: document.getElementById('edit-cpf').value },
            snapshot_employer: { nome_local: document.getElementById('edit-inst').value, nome_responsavel: document.getElementById('edit-resp').value },
            snapshot_event: { ...loadedRequests.find(r => r.id === id).snapshot_event, data_inicio: document.getElementById('edit-ini').value, data_fim: document.getElementById('edit-fim').value }
        };
        await updateDoc(doc(db, "exemption_requests", id), newData);
        document.getElementById('editModal').style.display = 'none';
        renderAdminDispensas(root);
    };

    window.deleteDispensa = async (id) => {
        if(confirm("Excluir pedido permanentemente?")) {
            await deleteDoc(doc(db, "exemption_requests", id));
            renderAdminDispensas(root);
        }
    };

    // A Mágica de Geração do PDF
    window.generateFinalPdf = async (id) => {
        const req = loadedRequests.find(r => r.id === id);
        const u = req.snapshot_user;
        let e = req.snapshot_event;
        const emp = req.snapshot_employer;

        // BUSCA A COMPETIÇÃO ORIGINAL NO BANCO PARA PEGAR O LOCAL ATUALIZADO
        try {
            if(req.competition_id) {
                const compDoc = await getDoc(doc(db, "competitions", req.competition_id));
                if(compDoc.exists()) {
                    const c = compDoc.data();
                    e.local = c.local || c.cidade || e.local; 
                    e.nome_campeonato = c.nome || c.name || e.nome_campeonato;
                    e.data_inicio = c.data_inicio || c.start_date || e.data_inicio;
                    e.data_fim = c.data_fim || c.end_date || e.data_fim;
                }
            }
        } catch(err) {
            console.warn("Aviso: não foi possível buscar os dados originais da competição", err);
        }

        const isM = u.genero === 'M';
        const formataData = (d) => {
            if(!d) return '';
            const parts = d.split('-');
            return parts.length === 3 ? `${parts[2]}/${parts[1]}/${parts[0]}` : d;
        };

  const dataMap = {
            "{{Datahoje}}": new Date().toLocaleDateString('pt-BR'),
            // 🔥 CORREÇÃO: Removido o 'A Instituição' daqui para não duplicar com o texto fixo
            "{{instituição}}": emp.nome_local || '', 
            "{{responsável}}": emp.nome_responsavel ? `A/C: ${emp.nome_responsavel}` : '',
            "{{pron_sr}}": isM ? "do Sr." : "da Sra.",
            "{{Nome}}": u.nome || u.nome_completo || '',
            "{{pron_registrado}}": isM ? "registrado" : "registrada",
            "{{CPF}}": u.cpf || '',
            "{{pron_portador}}": isM ? "portador" : "portadora",
            "{{RG}}": u.rg || '',
            "{{ÁRBITRO}}": (e.funcao || req.role_in_event || '').toUpperCase(),
            "{{COMPETIÇÃO}}": (e.nome_campeonato || '').toUpperCase(),
            "{{LOCAL}}": e.local || 'A definir',
            "{{Período1}}": formataData(e.data_inicio),
            "{{Período2}}": formataData(e.data_fim)
        };

        let finalHtml = currentTemplate;
        Object.keys(dataMap).forEach(tag => finalHtml = finalHtml.split(tag).join(dataMap[tag]));

        // Renderiza na memória
        const element = document.createElement('div');
        element.innerHTML = finalHtml;
        element.style.width = '800px'; 
        element.style.backgroundColor = '#ffffff';

        // Geração do nome do arquivo padronizado (Função_NomeCompleto_Competição.pdf)
        const funcaoName = (e.funcao || req.role_in_event || 'Funcao');
        const pessoaName = (u.nome || u.nome_completo || 'Arbitro');
        const compName = (e.nome_campeonato || 'Competicao');
        // Remove barras ou caracteres que possam bugar o download do Windows
        const pdfFileName = `${funcaoName}_${pessoaName}_${compName}.pdf`.replace(/[\/\\]/g, '-');

        const opt = {
            margin: 0, 
            filename: pdfFileName,
            image: { type: 'jpeg', quality: 1 },
            html2canvas: { scale: 2, useCORS: true, logging: false },
            jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
        };

        html2pdf().set(opt).from(element).save().then(() => {
            updateDoc(doc(db, "exemption_requests", id), { status: 'APPROVED' });
            window.__toast?.("PDF gerado com sucesso!", "success");
            renderAdminDispensas(document.getElementById('app'));
        }).catch(err => {
            console.error(err);
            alert("Erro ao processar as imagens Base64. Verifique se os códigos estão corretos.");
        });
    };
}